function fillOrderForBuyRequest(
uint totalTokensObtained,
uint initialEthersRemaining,
uint8 exchange,
address[5] orderAddresses,
uint[6] orderValues,
uint exchangeFee,
uint8 v,
bytes32 r,
bytes32 s
) internal returns(uint, uint)
{
uint tokensObtained = 0;
