tokensObtained = ZrxTrader.fillSellOrder(
orderAddresses,
orderValues,
fillAmount,
v,
r,
s
);
}
}


return (SafeMath.safeAdd(totalTokensObtained, tokensObtained), tokensObtained==0? initialEthersRemaining: ethersRemaining);
