!FundAccount(fundAccount).burn(xpaAssetToken, burnXPAAsset)
){
unPaidFundAccount[xpaAssetToken] = safeAdd(unPaidFundAccount[xpaAssetToken], burnXPAAsset);
}

}
return xpaAmount_;
}

